sql:
SELECT leader_name, COUNT(*) AS rating_count
FROM approval_ratings
GROUP BY leader_name;

SELECT demographic_rating_id, rating_id, approval_rating, confidence_level
FROM demographic_ratings
ORDER BY approval_rating DESC;

SELECT MAX(approval_rating) AS max_approval_rating
FROM demographic_ratings
WHERE demographic_id = 1;

SELECT leader_name
FROM approval_ratings
WHERE poll_id = 0;

SELECT approve
FROM approval_ratings
WHERE confidence_level >= 90.0;
